const weekAgo = new Date(); weekAgo.setDate(weekAgo.getDate()-7);
const recent = $input.all().map(i=>i.json).filter(r=>r.date && new Date(r.date)>=weekAgo);
return [{ json: { items: recent, count: recent.length, period: new Date().toISOString().slice(0,10) } }];

