const filter = $('Filter Past 7 Days').first().json;
let voc;
try { voc = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { voc = {}; }
return [{ json: { period: filter.period, count: filter.count, generated_at: new Date().toISOString(), ...voc } }];

